parameters.jsCode:
return items.map(item => {
  const row = item.json;

  const combinedRow = Object.entries(row)
    .map(([key, val]) => `${key}: ${val}`)
    .join(' | ');

  return {
    json: {
      combinedRow
    }
  };
});

